import os
import requests

def main(event):
    # Inputs from the HubSpot workflow
    job_uid = event["inputFields"]["job_uid"]
    deal_id = event["inputFields"]["deal_id"]

    # Secrets
    token = os.environ.get("token")  # HubSpot private app token
    zuper_api_key = os.environ.get("zuper_api_key")
    zuper_dc_region = os.environ.get("zuper_dc_region")

    # HubSpot portal ID — pulled from your example URL (21710069).
    # Consider moving this to an env var if it ever changes.
    hubspot_portal_id = "21710069"
    deal_link = f"https://app.hubspot.com/contacts/{hubspot_portal_id}/record/0-3/{deal_id}"

    base_url = f"https://{zuper_dc_region}.zuperpro.com/api/jobs"
    zuper_headers = {
        "accept": "application/json",
        "content-type": "application/json",
        "x-api-key": zuper_api_key,
    }

    # The two HubSpot fields we want to set on the Zuper job
    hubspot_fields = {
        "HubSpot Deal ID": str(deal_id),
        "Hubspot Deal Link": deal_link,
    }

    # ---- 1. GET the existing Zuper job to preserve its other custom_fields ----
    get_url = f"{base_url}/{job_uid}"
    get_resp = requests.get(get_url, headers=zuper_headers, timeout=30)

    try:
        get_resp.raise_for_status()
    except requests.exceptions.HTTPError as e:
        return {
            "outputFields": {
                "success": False,
                "stage": "zuper_get",
                "status_code": get_resp.status_code,
                "response": get_resp.text,
                "error": f"Zuper GET failed: {e}",
                "deal_link": deal_link,
            }
        }

    job_data = get_resp.json().get("data", {}) or {}
    existing_custom_fields = job_data.get("custom_fields", []) or []

    # ---- 2. Merge: update in place if label exists, otherwise append ----
    # Zuper matches custom fields by label, so this prevents duplicates
    # when the workflow runs more than once for the same deal.
    seen_labels = set()
    merged_fields = []

    for field in existing_custom_fields:
        label = field.get("label")
        if label in hubspot_fields:
            updated = dict(field)
            updated["value"] = hubspot_fields[label]
            merged_fields.append(updated)
            seen_labels.add(label)
        else:
            merged_fields.append(field)

    for label, value in hubspot_fields.items():
        if label not in seen_labels:
            merged_fields.append({"label": label, "value": value})

    # ---- 3. PUT the merged payload back to Zuper ----
    payload = {
        "job": {
            "job_uid": job_uid,
            "custom_fields": merged_fields,
        }
    }

    put_resp = requests.put(base_url, json=payload, headers=zuper_headers, timeout=30)

    try:
        put_resp.raise_for_status()
        zuper_response_body = put_resp.json()
    except requests.exceptions.HTTPError as e:
        return {
            "outputFields": {
                "success": False,
                "stage": "zuper_put",
                "status_code": put_resp.status_code,
                "response": put_resp.text,
                "error": f"Zuper PUT failed: {e}",
                "deal_link": deal_link,
            }
        }

    # ---- 4. Clear new_zuper_job_uid on the HubSpot deal ----
    # Only runs if the Zuper update succeeded — we don't want to clear the
    # trigger field if Zuper never got updated, or the deal would fall out
    # of the workflow with no record in either system.
    hubspot_url = f"https://api.hubapi.com/crm/v3/objects/deals/{deal_id}"
    hubspot_headers = {
        "accept": "application/json",
        "content-type": "application/json",
        "authorization": f"Bearer {token}",
    }
    hubspot_payload = {
        "properties": {
            "new_zuper_job_uid": "",  # empty string clears the property in HubSpot
        }
    }

    hs_resp = requests.patch(
        hubspot_url,
        json=hubspot_payload,
        headers=hubspot_headers,
        timeout=30,
    )

    try:
        hs_resp.raise_for_status()
        hubspot_cleared = True
        hubspot_error = None
    except requests.exceptions.HTTPError as e:
        hubspot_cleared = False
        hubspot_error = f"HubSpot PATCH failed: {e} — body: {hs_resp.text}"

    return {
        "outputFields": {
            "success": hubspot_cleared,
            "stage": "complete" if hubspot_cleared else "hubspot_clear",
            "zuper_status_code": put_resp.status_code,
            "hubspot_status_code": hs_resp.status_code,
            "hubspot_cleared": hubspot_cleared,
            "error": hubspot_error,
            "deal_link": deal_link,
            "fields_existed_before": len(existing_custom_fields),
            "fields_after_merge": len(merged_fields),
        }
    }
